SELECT e.employeeid, e.firstname, e.lastname, o.orderid, od.productid, p.categoryid, c.categoryname, o.orderdate FROM employees AS e JOIN orders AS o ON e.employeeid = o.employeeid JOIN "order details" AS od ON o.orderid = od.orderid JOIN products AS p ON od.productid = p.productid JOIN categories AS c ON p.categoryid = c.categoryid WHERE (c.categoryname = 'Beverages') AND (STRFTIME('%Y', o.orderdate) = '1997')
